INSERT INTO passages (id, title, topic, content, content_ja) VALUES (22, 'The Erosion of Democratic Norms in the Twenty-First Century', '政治',
INSERT INTO passage_questions (id, passage_id, question_number, question_type, question_text, explanation, correct_choice) VALUES
(64, 22, 1, 'comprehension', 'According to the passage, how does modern democratic erosion typically differ from past threats to democracy?', '第2段落で、「冷戦中に発展途上国を苦しめた軍事クーデターとは異なり、今日の民主主義の衰退は典型的に、内部からの制度の段階的な破壊を通じて起こる」と述べられている。現代の民主主義の侵食は、軍事クーデターではなく、選出されたリーダーによる内部からの段階的な制度の破壊によって特徴づけられる。', 4),
(65, 22, 2, 'fill_in_blank', 'Which of the following best fits in the blank [BLANK]?', '空所は第3段落の最終文にある。この段落は偽情報が民主主義を蝕む役割について論じており、直前の文で「誤解を招くナラティブを広め、敵意を煽り、信頼を侵食する」と述べている。したがって、市民が信頼できる情報と偽情報を区別することが困難になっている、という内容が最も適切である。', 1),
(66, 22, 3, 'comprehension', 'What does the passage suggest about the relationship between economic conditions and democratic stability?', '第4段落で、「民主的統治の正当性が具体的な経済的利益を提供する能力と不可分に結びついている」（the legitimacy of democratic governance is inextricably linked to its capacity to provide tangible economic benefits）と述べられている。経済的な繁栄を提供できない場合、国民はポピュリストリーダーに惹かれやすくなる。', 3);
INSERT INTO question_choices (question_id, choice_number, choice_text) VALUES
(64, 1, 'It is driven primarily by foreign military intervention rather than domestic factors.'),
(64, 2, 'It results from sudden constitutional amendments rather than incremental changes.'),
(64, 3, 'It is caused by economic crises that force governments to suspend elections.'),
(64, 4, 'It occurs gradually through the internal subversion of institutions by elected leaders.'),
(65, 1, 'distinguish between credible information and deliberate falsehoods'),
(65, 2, 'participate in elections without being influenced by campaign advertising'),
(65, 3, 'access social media platforms that are controlled by foreign governments'),
(65, 4, 'organize grassroots movements using traditional forms of communication'),
(66, 1, 'Economic conditions have no significant bearing on the stability of democratic governments.'),
(66, 2, 'Wealthy nations are completely immune to the threat of democratic backsliding.'),
(66, 3, 'Democratic legitimacy is closely tied to a government''s ability to deliver economic prosperity.'),
(66, 4, 'Economic inequality is a recent phenomenon that did not exist before the twenty-first century.');
